function StatCard({ icon: Icon, prefix = "", target, suffix = "", label, start }) {
  const [count, setCount] = useState(0);

  useEffect(() => {
    if (!start) return;
    let startTime;
    const duration = 1100;
    let frame;
    function step(ts) {
      if (!startTime) startTime = ts;
      const progress = Math.min((ts - startTime) / duration, 1);
      setCount(Math.floor(progress * target));
      if (progress < 1) frame = requestAnimationFrame(step);
    }
    frame = requestAnimationFrame(step);
    return () => cancelAnimationFrame(frame);
  }, [start, target]);

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: "8px", alignItems: "flex-start" }}>
      <div
        style={{
          width: "32px",
          height: "32px",
          borderRadius: "50%",
          background: "rgba(126,193,234,0.12)",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
        }}
      >
        <Icon size={16} color="#7EC1EA" strokeWidth={1.75} />
      </div>
      <p style={{ fontFamily: "'IBM Plex Mono', monospace", fontWeight: 500, fontSize: "26px", color: COLORS.paper, margin: 0 }}>
        {prefix}
        {count}
        {suffix}
      </p>
      <p style={{ fontFamily: "'Inter', sans-serif", fontSize: "12.5px", color: COLORS.paperDim, margin: 0, lineHeight: 1.35 }}>
        {label}
      </p>
    </div>
  );
}

