function TestimonialCarousel() {
  const [startIndex, setStartIndex] = useState(0);
  const [paused, setPaused] = useState(false);
  const visibleCount = Math.min(3, TESTIMONIALS.length);

  useEffect(() => {
    if (paused || TESTIMONIALS.length <= visibleCount) return;
    const timer = setInterval(() => {
      setStartIndex((i) => (i + 1) % TESTIMONIALS.length);
    }, 10000);
    return () => clearInterval(timer);
  }, [paused, visibleCount]);

  const visible = Array.from(
    { length: visibleCount },
    (_, k) => TESTIMONIALS[(startIndex + k) % TESTIMONIALS.length]
  );

  return (
    <div
      onMouseEnter={() => setPaused(true)}
      onMouseLeave={() => setPaused(false)}
      style={{ maxWidth: "1040px", margin: "0 auto" }}
    >
      <div
        key={startIndex}
        style={{ display: "flex", flexWrap: "wrap", gap: "20px", animation: "fadeInTestimonials 0.5s ease" }}
      >
        {visible.map((t, i) => (
          <TestimonialCard key={`${startIndex}-${i}`} name={t.name} flag={t.flag} text={t.text} />
        ))}
      </div>

      {TESTIMONIALS.length > visibleCount && (
        <div style={{ display: "flex", justifyContent: "center", gap: "8px", marginTop: "26px" }}>
          {TESTIMONIALS.map((_, i) => (
            <button
              key={i}
              onClick={() => setStartIndex(i)}
              aria-label={`Ir al testimonio ${i + 1}`}
              style={{
                width: "8px",
                height: "8px",
                borderRadius: "50%",
                border: "none",
                padding: 0,
                cursor: "pointer",
                background: i === startIndex ? COLORS.blue : "rgba(242,238,227,0.3)",
              }}
            />
          ))}
        </div>
      )}
    </div>
  );
}

